{
  description = "Vellum Core Toolchain";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
  };

  outputs = { self, nixpkgs }: let
    system = "x86_64-linux";
    pkgs = nixpkgs.legacyPackages.${system};
  in {
    lib = {
      copyFlac = ''find . -maxdepth 2 -name "*.flac" -exec cp {} $out/ \;'';

      mkAlbum = { 
        pname, 
        sourceDisk ? null,
        sourceTorrent ? null,
        sourceMagnet ? null,
        sha256 ? null,
        fetchCommand ? null,
        metadata ? null, 
        metadataString ? null, 
        cover ? null, 
        ops ? self.lib.copyFlac
      }:
        let
          unwrap = s: if builtins.isString s && builtins.substring 0 1 s == "/" 
                      then /. + s 
                      else s;

          rawSrc = if (builtins.getEnv "VELLUM_STAGING_SRC") != "" then
                      /. + (builtins.getEnv "VELLUM_STAGING_SRC")
                    else if sourceDisk != null then 
                      unwrap sourceDisk
                    else 
                      throw "No source found for ${pname}";

          realSrc = builtins.path { 
            name = "${pname}-source"; 
            path = rawSrc; 
            inherit sha256; 
          };

          realMetadata = if metadata != null 
                         then builtins.path { name = "${pname}-metadata"; path = unwrap metadata; } 
                         else null;

          realCover = if cover != null 
                      then builtins.path { name = "${pname}-cover"; path = unwrap cover; } 
                      else null;

          coverExt = if cover != null then 
                       let 
                         base = builtins.baseNameOf (unwrap cover);
                         match = builtins.match ".*\\.([^.]+)$" base;
                       in if match != null then builtins.elemAt match 0 else "img"
                     else "";
        in
        pkgs.stdenv.mkDerivation {
          name = pname;
          src = realSrc;

          metadataPath = realMetadata;
          metadataContent = metadataString;
          coverPath = realCover;
          ext = coverExt;

          buildInputs = [ pkgs.flac pkgs.shntool pkgs.ffmpeg ];

          passAsFile = if metadataString != null then [ "metadataContent" ] else [];

          passthru = {
            inherit pname sourceMagnet sourceTorrent sha256 fetchCommand;
            sourceDisk = if (builtins.getEnv "VELLUM_STAGING_SRC") != "" then (builtins.getEnv "VELLUM_STAGING_SRC") else sourceDisk;
            usingMetadataFile = metadata != null;
          };

          buildPhase = ''
            mkdir -p $out

            if [ -d "$src" ]; then
              cd "$src"
            fi

            ${ops}

            if [ -n "$metadataPath" ]; then
              cp "$metadataPath" "$out/metadata.toml"
            elif [ -n "''${metadataContentPath:-}" ] && [ -f "$metadataContentPath" ]; then
              cp "$metadataContentPath" "$out/metadata.toml"
            fi

            if [ -n "$coverPath" ]; then
              cp "$coverPath" "$out/cover.$ext"
            fi
          '';

          installPhase = "true";
        };
    };
  };
}



#version 300 es
precision highp float;
precision highp int;

#ifndef NUM_COLORS
#define NUM_COLORS 24
#endif

uniform float iTime;
uniform float iRandom;
uniform vec2 iResolution;
uniform float iCoverSize;
uniform vec3 iColorsOklab[NUM_COLORS];
uniform float iRatios[NUM_COLORS];
uniform int iCount;

uniform float iSpeed;
uniform float iZoom;
uniform float iBlur;
uniform float iGrain;

out vec4 fragColor;

vec3 oklab_to_srgb(vec3 c) {
    float l_ = c.x + 0.3963377774 * c.y + 0.2158037573 * c.z;
    float m_ = c.x - 0.1055613458 * c.y - 0.0638541728 * c.z;
    float s_ = c.x - 0.0894841775 * c.y - 1.2914855480 * c.z;

    float l = l_ * l_ * l_;
    float m = m_ * m_ * m_;
    float s = s_ * s_ * s_;

    float r = +4.0767416621 * l - 3.3077115913 * m + 0.2309699292 * s;
    float g = -1.2684380046 * l + 2.6097574011 * m - 0.3413193965 * s;
    float b = -0.0041960863 * l - 0.7034186147 * m + 1.7076147010 * s;

    r = r >= 0.0031308 ? 1.055 * pow(r, 1.0 / 2.4) - 0.055 : 12.92 * r;
    g = g >= 0.0031308 ? 1.055 * pow(g, 1.0 / 2.4) - 0.055 : 12.92 * g;
    b = b >= 0.0031308 ? 1.055 * pow(b, 1.0 / 2.4) - 0.055 : 12.92 * b;

    return clamp(vec3(r, g, b), 0.0, 1.0);
}

vec4 permute(vec4 x){return mod(((x*34.0)+1.0)*x, 289.0);}
vec4 taylorInvSqrt(vec4 r){return 1.79284291400159 - 0.85373472095314 * r;}

float snoise(vec3 v){ 
  const vec2  C = vec2(1.0/6.0, 1.0/3.0) ;
  const vec4  D = vec4(0.0, 0.5, 1.0, 2.0);

  vec3 i  = floor(v + dot(v, C.yyy) );
  vec3 x0 =   v - i + dot(i, C.xxx) ;

  vec3 g = step(x0.yzx, x0.xyz);
  vec3 l = 1.0 - g;
  vec3 i1 = min( g.xyz, l.zxy );
  vec3 i2 = max( g.xyz, l.zxy );

  vec3 x1 = x0 - i1 + 1.0 * C.xxx;
  vec3 x2 = x0 - i2 + 2.0 * C.xxx;
  vec3 x3 = x0 - D.yyy;

  i = mod(i, 289.0); 
  vec4 p = permute( permute( permute( 
             i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
           + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
           + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

  float n_ = 1.0/7.0;
  vec3  ns = n_ * D.wyz - D.xzx;

  vec4 j = p - 49.0 * floor(p * ns.z *ns.z);

  vec4 x_ = floor(j * ns.z);
  vec4 y_ = floor(j - 7.0 * x_ );

  vec4 x = x_ *ns.x + ns.yyyy;
  vec4 y = y_ *ns.x + ns.yyyy;
  vec4 h = 1.0 - abs(x) - abs(y);

  vec4 b0 = vec4( x.xy, y.xy );
  vec4 b1 = vec4( x.zw, y.zw );

  vec4 s0 = floor(b0)*2.0 + 1.0;
  vec4 s1 = floor(b1)*2.0 + 1.0;
  vec4 sh = -step(h, vec4(0.0));

  vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
  vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

  vec3 p0 = vec3(a0.xy,h.x);
  vec3 p1 = vec3(a0.zw,h.y);
  vec3 p2 = vec3(a1.xy,h.z);
  vec3 p3 = vec3(a1.zw,h.w);

  vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
  p0 *= norm.x;
  p1 *= norm.y;
  p2 *= norm.z;
  p3 *= norm.w;

  vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
  m = m * m;
  return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                dot(p2,x2), dot(p3,x3) ) );
}

float fbm(vec3 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 3; i++) {
        v += a * snoise(p);
        p *= 2.0;
        a *= 0.5;
    }

    // Normalize using the practical peak (0.55) instead of the 
    // impossible theoretical peak (0.875). Clamp to prevent overshoot.
    v = v / 0.75;
    v = clamp(v, -1.0, 1.0);

    v = v * 0.5 + 0.5;
    v = 0.5 - 0.5 * cos(3.14159265 * v);

    return v;
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    float aspect = iResolution.x / iResolution.y;
    vec2 p = (uv - 0.5);
    p.x *= aspect;

    float t = (iTime + iRandom) * iSpeed / 100.0;

    float val = fbm(vec3(p * iZoom, t));

    vec3 finalOklab = vec3(0.0);

    float segmentWidth = 1.0 / float(max(1, iCount));
    float edgeSoftness = iBlur * segmentWidth * 1.0;

    for(int i = 0; i < NUM_COLORS; i++) {
        if (i >= iCount) break;

        float cumulative = float(i) * segmentWidth;
        float nextCumulative = float(i + 1) * segmentWidth;

        float startMask = (i == 0) ? 1.0 : smoothstep(cumulative - edgeSoftness, cumulative + edgeSoftness, val);
        float endMask = (i == iCount - 1) ? 0.0 : smoothstep(nextCumulative - edgeSoftness, nextCumulative + edgeSoftness, val);

        float weightMask = startMask - endMask;

        finalOklab += iColorsOklab[i] * max(0.0, weightMask);
    }

    finalOklab.x = 0.05 + (finalOklab.x * 0.9);

    vec3 finalColor = oklab_to_srgb(finalOklab);

    float grain = (fract(sin(dot(uv, vec2(12.9898, 78.233))) * 43758.5453) - 0.5) * iGrain / 10.0;
    finalColor += grain;

    fragColor = vec4(finalColor, 1.0);
}



#version 300 es
precision highp float;
precision highp int;

#ifndef NUM_COLORS
#define NUM_COLORS 24
#endif

uniform float iTime;
uniform float iRandom;
uniform vec2 iResolution;
uniform float iCoverSize;
uniform vec3 iColorsOklab[NUM_COLORS];
uniform float iRatios[NUM_COLORS];
uniform int iCount;

uniform float iSpeed;
uniform float iZoom;
uniform float iBlur;
uniform float iGrain;

out vec4 fragColor;

vec3 oklab_to_srgb(vec3 c) {
    float l_ = c.x + 0.3963377774 * c.y + 0.2158037573 * c.z;
    float m_ = c.x - 0.1055613458 * c.y - 0.0638541728 * c.z;
    float s_ = c.x - 0.0894841775 * c.y - 1.2914855480 * c.z;

    float l = l_ * l_ * l_;
    float m = m_ * m_ * m_;
    float s = s_ * s_ * s_;

    float r = +4.0767416621 * l - 3.3077115913 * m + 0.2309699292 * s;
    float g = -1.2684380046 * l + 2.6097574011 * m - 0.3413193965 * s;
    float b = -0.0041960863 * l - 0.7034186147 * m + 1.7076147010 * s;

    r = r >= 0.0031308 ? 1.055 * pow(r, 1.0 / 2.4) - 0.055 : 12.92 * r;
    g = g >= 0.0031308 ? 1.055 * pow(g, 1.0 / 2.4) - 0.055 : 12.92 * g;
    b = b >= 0.0031308 ? 1.055 * pow(b, 1.0 / 2.4) - 0.055 : 12.92 * b;

    return clamp(vec3(r, g, b), 0.1, 0.8);
}

vec4 permute(vec4 x){return mod(((x*34.0)+1.0)*x, 289.0);}
vec4 taylorInvSqrt(vec4 r){return 1.79284291400159 - 0.85373472095314 * r;}

float snoise(vec3 v){ 
  const vec2  C = vec2(1.0/6.0, 1.0/3.0) ;
  const vec4  D = vec4(0.0, 0.5, 1.0, 2.0);

  vec3 i  = floor(v + dot(v, C.yyy) );
  vec3 x0 =   v - i + dot(i, C.xxx) ;

  vec3 g = step(x0.yzx, x0.xyz);
  vec3 l = 1.0 - g;
  vec3 i1 = min( g.xyz, l.zxy );
  vec3 i2 = max( g.xyz, l.zxy );

  vec3 x1 = x0 - i1 + 1.0 * C.xxx;
  vec3 x2 = x0 - i2 + 2.0 * C.xxx;
  vec3 x3 = x0 - D.yyy;

  i = mod(i, 289.0); 
  vec4 p = permute( permute( permute( 
             i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
           + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
           + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

  float n_ = 1.0/7.0;
  vec3  ns = n_ * D.wyz - D.xzx;

  vec4 j = p - 49.0 * floor(p * ns.z *ns.z);

  vec4 x_ = floor(j * ns.z);
  vec4 y_ = floor(j - 7.0 * x_ );

  vec4 x = x_ *ns.x + ns.yyyy;
  vec4 y = y_ *ns.x + ns.yyyy;
  vec4 h = 1.0 - abs(x) - abs(y);

  vec4 b0 = vec4( x.xy, y.xy );
  vec4 b1 = vec4( x.zw, y.zw );

  vec4 s0 = floor(b0)*2.0 + 1.0;
  vec4 s1 = floor(b1)*2.0 + 1.0;
  vec4 sh = -step(h, vec4(0.0));

  vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
  vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

  vec3 p0 = vec3(a0.xy,h.x);
  vec3 p1 = vec3(a0.zw,h.y);
  vec3 p2 = vec3(a1.xy,h.z);
  vec3 p3 = vec3(a1.zw,h.w);

  vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
  p0 *= norm.x;
  p1 *= norm.y;
  p2 *= norm.z;
  p3 *= norm.w;

  vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
  m = m * m;
  return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                dot(p2,x2), dot(p3,x3) ) );
}

float fbm(vec3 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 3; i++) {
        v += a * snoise(p);
        p *= 2.0;
        a *= 0.5;
    }

    v = v / 0.875;
    v = v * 0.5 + 0.5;
    v = 0.5 - 0.5 * cos(3.14159265 * v);
    v = 0.5 - 0.5 * cos(3.14159265 * v);

    return clamp(v, 0.0, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    float aspect = iResolution.x / iResolution.y;
    vec2 p = (uv - 0.5);
    p.x *= aspect;

    float t = (iTime + iRandom) * iSpeed;

    float val = fbm(vec3(p * iZoom, t));

    float totalWeight = 0.0;
    for(int i = 0; i < NUM_COLORS; i++) {
        totalWeight += iRatios[i];
    }
    if (totalWeight <= 0.0) totalWeight = 1.0; 

    vec3 finalOklab = vec3(0.0);
    float cumulative = 0.00;
    float currentEdgeSoftness = 0.0;

    for(int i = 0; i < NUM_COLORS; i++) {
        float weight = iRatios[i] / totalWeight;
        float nextCumulative = cumulative + weight;

        float nextWeight = 0.0;
        if (i + 1 < NUM_COLORS) {
            nextWeight = iRatios[i+1] / totalWeight;
        }

        float nextEdgeSoftness = iBlur * min(weight, nextWeight); 

        float startMask = (i == 0) ? 1.0 : smoothstep(cumulative - currentEdgeSoftness, cumulative + currentEdgeSoftness, val);
        float endMask = (i == NUM_COLORS - 1) ? 0.0 : smoothstep(nextCumulative - nextEdgeSoftness, nextCumulative + nextEdgeSoftness, val);

        float weightMask = startMask - endMask;

        finalOklab += iColorsOklab[i] * max(0.0, weightMask);

        cumulative = nextCumulative;
        currentEdgeSoftness = nextEdgeSoftness;
    }

    finalOklab.x = 0.0 + (finalOklab.x * 0.7);

    vec3 finalColor = oklab_to_srgb(finalOklab);

    float grain = (fract(sin(dot(uv, vec2(12.9898, 78.233))) * 43758.5453) - 0.5) * iGrain;
    finalColor += grain;

    fragColor = vec4(finalColor, 1.0);
}



#version 300 es
precision highp float;
precision highp int;

#ifndef NUM_COLORS
#define NUM_COLORS 24
#endif

uniform float iTime;
uniform float iRandom;
uniform vec2 iResolution;
uniform float iCoverSize;
uniform vec3 iColorsOklab[NUM_COLORS];
uniform float iRatios[NUM_COLORS];
uniform int iCount;

uniform float iSpeed;
uniform float iZoom;
uniform float iBlur;
uniform float iEdgeBlur;
uniform float iGrain;

out vec4 fragColor;

const float SPEED = 0.02;
const float GRAIN_AMOUNT = 0.02;
const float N = 24.0; 

vec3 oklab_to_srgb(vec3 c) {
    float l_ = c.x + 0.3963377774 * c.y + 0.2158037573 * c.z;
    float m_ = c.x - 0.1055613458 * c.y - 0.0638541728 * c.z;
    float s_ = c.x - 0.0894841775 * c.y - 1.2914855480 * c.z;

    float l = l_ * l_ * l_;
    float m = m_ * m_ * m_;
    float s = s_ * s_ * s_;

    float r = +4.0767416621 * l - 3.3077115913 * m + 0.2309699292 * s;
    float g = -1.2684380046 * l + 2.6097574011 * m - 0.3413193965 * s;
    float b = -0.0041960863 * l - 0.7034186147 * m + 1.7076147010 * s;

    r = r >= 0.0031308 ? 1.055 * pow(r, 1.0 / 2.4) - 0.055 : 12.92 * r;
    g = g >= 0.0031308 ? 1.055 * pow(g, 1.0 / 2.4) - 0.055 : 12.92 * g;
    b = b >= 0.0031308 ? 1.055 * pow(b, 1.0 / 2.4) - 0.055 : 12.92 * b;

    return clamp(vec3(r, g, b), 0.0, 1.0);
}

float hash(vec2 p) {
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 4; i++) {
        v += a * noise(p);
        p *= 2.0;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    float aspect = iResolution.x / iResolution.y;
    vec2 p = uv;
    p.x *= aspect;

    float t = (iTime + iRandom) * SPEED;

    vec2 center = vec2(0.5 * aspect, 0.5);
    float dist = length(p - center);
    float cRad = (iCoverSize / iResolution.y) * 0.5;

    p += (p - center) * smoothstep(cRad + 0.5, cRad - 0.1, dist) * 0.3;

    float val = fbm(p * 1.5 + t);
    val = clamp(val, 0.0, 1.0);

    float totalWeight = 0.0;
    for(int i = 0; i < NUM_COLORS; i++) {
        if (i >= iCount) break;
        totalWeight += 1.0 / (float(i) + N);
    }

    vec3 finalColor = vec3(0.0);
    float softness = 0.125; 
    float cumulative = 0.0;

    for(int i = 0; i < NUM_COLORS; i++) {
        if (i >= iCount) break;

        float weight = (1.0 / (float(i) + N)) / totalWeight;
        float nextCumulative = cumulative + weight;

        float weightMask = smoothstep(cumulative - softness, cumulative + softness, val) - 
                           smoothstep(nextCumulative - softness, nextCumulative + softness, val);

        finalColor += oklab_to_srgb(iColorsOklab[i]) * max(0.0, weightMask);
        cumulative = nextCumulative;
    }

    float noiseFloor = (hash(uv + iTime) - 0.5) * GRAIN_AMOUNT;
    finalColor += noiseFloor;

    fragColor = vec4(finalColor, 1.0);
}



#version 300 es

// WebGL 2.0 fragment shader for generating organic, fluid background visuals.
// Utilizes perceptual color spaces to avoid muddy transitions during interpolation.
precision highp float;
precision highp int;

// Define maximum palette size to match the uniform array allocation in the engine.
#ifndef NUM_COLORS
#define NUM_COLORS 24
#endif

// Animation clock in seconds.
uniform float iTime;
// Seed value used to ensure distinct noise patterns for different albums.
uniform float iRandom;
// Viewport resolution used for coordinate normalization.
uniform vec2 iResolution;
// Physical size of the album cover for potential parallax/occlusion logic.
uniform float iCoverSize;
// Palette colors stored in Oklab space for perceptually uniform blending.
uniform vec3 iColorsOklab[NUM_COLORS];
// The statistical representation ratio of each color in the source image.
uniform float iRatios[NUM_COLORS];
// Number of active colors in the current palette.
uniform int iCount;

// Multiplier for the temporal noise coordinate.
uniform float iSpeed;
// Scale factor for the spatial noise coordinates.
uniform float iZoom;
// Controls the falloff power of color weights to adjust blending sharpness.
uniform float iBlur;
// Strength of the high-frequency grain overlay.
uniform float iGrain;

out vec4 fragColor;

// Converts Oklab coordinates to linear sRGB then to gamma-corrected sRGB.
// This prevents the "gray mud" effect in mid-tones common with standard RGB blending.
vec3 oklab_to_srgb(vec3 c) {
    float l_ = c.x + 0.3963377774 * c.y + 0.2158037573 * c.z;
    float m_ = c.x - 0.1055613458 * c.y - 0.0638541728 * c.z;
    float s_ = c.x - 0.0894841775 * c.y - 1.2914855480 * c.z;

    float l = l_ * l_ * l_;
    float m = m_ * m_ * m_;
    float s = s_ * s_ * s_;

    float r = +4.0767416621 * l - 3.3077115913 * m + 0.2309699292 * s;
    float g = -1.2684380046 * l + 2.6097574011 * m - 0.3413193965 * s;
    float b = -0.0041960863 * l - 0.7034186147 * m + 1.7076147010 * s;

    r = r >= 0.0031308 ? 1.055 * pow(r, 1.0 / 2.4) - 0.055 : 12.92 * r;
    g = g >= 0.0031308 ? 1.055 * pow(g, 1.0 / 2.4) - 0.055 : 12.92 * g;
    b = b >= 0.0031308 ? 1.055 * pow(b, 1.0 / 2.4) - 0.055 : 12.92 * b;

    return clamp(vec3(r, g, b), 0.0, 1.0);
}

// Standard helper functions for Simplex noise implementation.
vec4 permute(vec4 x){return mod(((x*34.0)+1.0)*x, 289.0);}
vec4 taylorInvSqrt(vec4 r){return 1.79284291400159 - 0.85373472095314 * r;}

// Implementation of 3D Simplex noise for fluid motion and spatial variance.
float snoise(vec3 v){ 
  const vec2  C = vec2(1.0/6.0, 1.0/3.0) ;
  const vec4  D = vec4(0.0, 0.5, 1.0, 2.0);

  vec3 i  = floor(v + dot(v, C.yyy) );
  vec3 x0 =   v - i + dot(i, C.xxx) ;

  vec3 g = step(x0.yzx, x0.xyz);
  vec3 l = 1.0 - g;
  vec3 i1 = min( g.xyz, l.zxy );
  vec3 i2 = max( g.xyz, l.zxy );

  vec3 x1 = x0 - i1 + 1.0 * C.xxx;
  vec3 x2 = x0 - i2 + 2.0 * C.xxx;
  vec3 x3 = x0 - D.yyy;

  i = mod(i, 289.0); 
  vec4 p = permute( permute( permute( 
             i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
           + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
           + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

  float n_ = 1.0/7.0;
  vec3  ns = n_ * D.wyz - D.xzx;

  vec4 j = p - 49.0 * floor(p * ns.z *ns.z);

  vec4 x_ = floor(j * ns.z);
  vec4 y_ = floor(j - 7.0 * x_ );

  vec4 x = x_ *ns.x + ns.yyyy;
  vec4 y = y_ *ns.x + ns.yyyy;
  vec4 h = 1.0 - abs(x) - abs(y);

  vec4 b0 = vec4( x.xy, y.xy );
  vec4 b1 = vec4( x.zw, y.zw );

  vec4 s0 = floor(b0)*2.0 + 1.0;
  vec4 s1 = floor(b1)*2.0 + 1.0;
  vec4 sh = -step(h, vec4(0.0));

  vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
  vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

  vec3 p0 = vec3(a0.xy,h.x);
  vec3 p1 = vec3(a0.zw,h.y);
  vec3 p2 = vec3(a1.xy,h.z);
  vec3 p3 = vec3(a1.zw,h.w);

  vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
  p0 *= norm.x;
  p1 *= norm.y;
  p2 *= norm.z;
  p3 *= norm.w;

  vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
  m = m * m;
  return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                dot(p2,x2), dot(p3,x3) ) );
}

// Fractional Brownian Motion using 2 octaves. 
// Provides enough detail for fluid movement while minimizing GPU texture unit usage.
float fbm(vec3 p) {
    float v = 0.0;
    float a = 4.2;
    for (int i = 0; i < 2; i++) {
        v += a * snoise(p);
        p *= 2.0;
        a *= 0.5;
    }
    return v / 0.75;
}

void main() {
    // Coordinate normalization with aspect ratio correction.
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    float aspect = iResolution.x / iResolution.y;
    vec2 p = uv - 0.5;
    p.x *= aspect;

    // Apply speed multiplier to the global time variable.
    float t = (iTime + iRandom) * iSpeed;

    // Limit active palette processing to 12 for mobile performance and power efficiency.
    int limit = iCount;
    if (limit > 12) limit = 12;
    if (limit == 0) {
        fragColor = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    float totalWeight = 0.0001;
    vec3 finalOklab = iColorsOklab[0] * totalWeight;

    // Convert the 0.0-1.0 iBlur parameter into an exponential power factor.
    // Higher power creates sharper "islands" of color; lower power creates a misty blend.
    float power = max(0.0, 10.0 - iBlur * 13.0);

    for (int i = 0; i < limit; i++) {
        float fi = float(i);

        // Calculate a unique spatial offset for every color index using prime-like constants.
        // This prevents different colors from sharing the exact same noise pattern.
        vec2 offset = vec2(sin(t * 0.5 + fi * 1.3), cos(t * 0.4 + fi * 2.1)) * 0.5;
        vec3 p3 = vec3(p * iZoom + offset + vec2(fi * 13.37, fi * 27.51), t + fi * 42.1);

        // Sample noise and remap to 0.0 - 1.0 range.
        float n = fbm(p3);
        n = n * 0.5 + 0.5;

        // Apply the weight power to create localized clumping of specific palette colors.
        float w = pow(max(0.0, n), power);

        finalOklab += iColorsOklab[i] * w;
        totalWeight += w;
    }

    // Normalize sum of weights back to a valid Oklab color.
    finalOklab /= totalWeight;

    // Final color space conversion to sRGB for display.
    vec3 finalColor = oklab_to_srgb(finalOklab);

    // Apply high-frequency noise (grain) to dither the 8-bit output.
    // This masks banding artifacts in smooth gradients produced by the Oklab transitions.
    float grain = (fract(sin(dot(uv, vec2(12.9898, 78.233))) * 43758.5453) - 0.5) * iGrain;
    finalColor += grain;

    fragColor = vec4(finalColor, 1.0);
}



