[storage]
library_root = "/run/media/lewelove/1000xhome/backup-everything/FB2K/Library Historyfied!/"
library_export = "~/dev/vellum-test-library/metadata_output"
environment = "~/.secrets/vellum.env"


[nix]
flake = "/home/lewelove/dev/vellum/nix/flake.nix"
store = "/run/media/lewelove/1000xhome/backup-everything/FB2K/.vellum/store/"
stage = "/run/media/lewelove/1000xhome/backup-everything/FB2K/.vellum/stage/"

[nix.commands]
get_torrent = "transmission-remote -a '${sourceTorrent.file}' -w '${sourceDisk.path}'"
verify_torrent = "imdl -q torrent verify '${sourceTorrent.file}' --content '${sourceDisk.path}/${sourceTorrent.name}/'"
seed_torrent = ""


[theme]
thumbnail_size = 190


[theme.shader]
order = "original"
path = "shaders/mountain_eq.frag"
speed = 0.5
zoom = 0.2
blur = 0.6
grain = 0.2

# path = "shaders/simplex.frag"
# speed = 0.005
# zoom = 0.8
# blur = 0.00


[manifest]
supported_extensions = [ ".flac" ]


[compiler]
unix_added = [ "unix_added_youtube", "unix_added_applemusic", "unix_added_foobar" ]
date_added = "%B %d %Y"
manifests = [ "mbid.toml", "cover_palette.toml" ]
file_subset_match = [
  "album", "albumartist", "date", "genre",
  "comment", "title", "artist", "tracknumber",
  "musicbrainz_albumartistid", "musicbrainz_albumid",
  "musicbrainz_releasegroupid", "musicbrainz_artistid",
  "musicbrainz_releasetrackid", "musicbrainz_trackid"
]


[compiler.cover_palette]
# type = "kmeansnh"
# sort = "gradient"
# args = "k=18,n=6,h=5"
type = "kmeansnv"
# sort = "original"
# threshold = 0.02
args = "k=12,n=12,d=0.0"


[manifest.keys]
albumartist = { level = "album", newline = true }
album = { level = "album" }
date = { level = "album" }

genre = { level = "album", type = "list", newline = true }
styles = { level = "album", type = "list" }

original_yyyy_mm = { level = "album", newline = true }

country = { level = "album", newline = true }
label = { level = "album" }
catalognumber = { level = "album" }
release_yyyy_mm = { level = "album" }

discogs_url = { level = "album", newline = true }
musicbrainz_url = { level = "album" }
ctdbid_url = { level = "album" }

tracknumber = { level = "track" }
title = { level = "track" }


[compiler.keys]
albumartists = { level = "album", type = "list" }
styles = { level = "album", type = "list" }
country = { level = "album" }
label = { level = "album" }
catalognumber = { level = "album" }
media = { level = "album" }
discogs_url = { level = "album" }
musicbrainz_url = { level = "album" }
ctdbid_url = { level = "album" }
unix_added_foobar = { level = "album", type = "integer" }
unix_added_applemusic = { level = "album", type = "integer" }
unix_added_youtube = { level = "album", type = "integer" }
custom_id = { level = "album" }
custom_albumartist = { level = "album", args = "custom_albumartist,artistartist,albumartist" }
custom_string = { level = "album" }
old_comment = { level = "album" }
collection = { level = "album", type = "list" }
shelves = { level = "album", type = "list" }
my_year = { level = "album", type = "list" }
replaygain_album_gain = { level = "album" }
replaygain_album_peak = { level = "album" }
musicbrainz_albumid = { level = "album" }
musicbrainz_albumartistid = { level = "album" }
musicbrainz_releasegroupid = { level = "album" }

lyrics = { level = "tracks" }
accuripid = { level = "tracks" }
ctdbid = { level = "tracks" }
discid = { level = "tracks" }
instrumental = { level = "tracks", type = "bool" }
replaygain_track_gain = { level = "tracks" }
replaygain_track_peak = { level = "tracks" }
musicbrainz_trackid = { level = "tracks" }
musicbrainz_releasetrackid = { level = "tracks" }
musicbrainz_artistid = { level = "tracks" }

cover_chroma = { level = "album", class = "function" }
cover_entropy = { level = "album", class = "function" }
# cover_palette = { level = "album", class = "function", args = "k=12,noise=0.0,conv=0.05,filter=0.002,bias=0.0" }
# cover_palette = { level = "album", class = "function", args = "type=kmeans,sort=C,k=8" }
# cover_palette = { level = "album", class = "function", args = "type=kmeans,sort=gradient,k=8,Hb=35,Ht=108,Cb=12,Ct=60,Tb=0,Tt=50" }
# cover_palette = { level = "album", class = "function", args = "type=msc,k=16,bw=0.08,mt=0.05,cg=3.0,t=0.002" }
# cover_palette = { level = "album", class = "function", args = "type=mmcq,k=8,sort=C" }
# cover_palette = { level = "album", class = "function", args = "type=auto,theme=basic,t=0.0,k=12" }
# cover_palette = { level = "album", class = "function", args = "type=msc,bw=6" }



# -- GROUPERS --

[groupers.genre]
label = "Genre"
select = "${album.genre}"

[groupers.artists]
label = "Artists"
select = "COALESCE(NULLIF(${album.tags.albumartists}, {[]}), ${album.albumartist})"
index = true

[groupers.decade]
label = "Decade"
select = "substr(${album.date}, 1, 3) || {0s}"

[groupers.total_tracks]
label = "Total Tracks"
select = "CAST(${album.info.total_tracks} AS TEXT)"

[groupers.total_discs]
label = "Total Discs"
select = "CAST(COALESCE(${album.info.total_discs}, 1) AS TEXT)"

[groupers.year_added]
label = "Year Added"
select = "strftime({%Y}, datetime(${album.info.unix_added}, {unixepoch}))"

[groupers.chroma]
label = "Chroma"
select = "CASE WHEN CAST(${album.tags.cover_chroma} AS FLOAT) = 0 THEN {Monochrome} WHEN CAST(${album.tags.cover_chroma} AS FLOAT) < 15 THEN {Bleak} WHEN CAST(${album.tags.cover_chroma} AS FLOAT) < 33 THEN {Muted} WHEN CAST(${album.tags.cover_chroma} AS FLOAT) < 60 THEN {Standard} ELSE {Vibrant} END"

# -- SORTERS --

[sorters.default]
label = "Default"
order_by = "CASE WHEN LOWER(COALESCE(${album.tags.custom_albumartist}, ${album.albumartist})) LIKE {the %} THEN SUBSTR(COALESCE(${album.tags.custom_albumartist}, ${album.albumartist}), 5) ELSE COALESCE(${album.tags.custom_albumartist}, ${album.albumartist}) END ASC, ${album.date} ASC, ${album.album} ASC"

[sorters.az]
label = "Alphabetical"
order_by = "${album.album} ASC"

[sorters.year]
label = "Year"
order_by = "${album.date} DESC"

[sorters.duration]
label = "Duration"
order_by = "CAST(${album.info.album_duration} AS INT) DESC"

[sorters.chroma]
label = "Chroma"
order_by = "CAST(${album.tags.cover_chroma} AS FLOAT) DESC"

[sorters.entropy]
label = "Entropy"
order_by = "CAST(${album.tags.cover_entropy} AS INT) DESC"

[sorters.date_added]
label = "Date Added"
order_by = "COALESCE(CAST(${album.tags.unix_added_youtube} AS INT), CAST(${album.tags.unix_added_applemusic} AS INT), CAST(${album.tags.unix_added_foobar} AS INT), CAST(${album.info.unix_added} AS INT)) DESC"

[sorters.last_edited]
label = "Last Edited"
order_by = "COALESCE(${album.info.metadata_toml_mtime}, 0) DESC"

# -- COLLECTIONS --

# [collections.library]
# label = "Entire Library"
# filter = "1=1"

[collections.album_library]
label = "Main Library"
filter = "COALESCE(${album.tags.collection}, '') NOT LIKE %{Vapor Memory} AND ${album.genre} NOT LIKE %{Signalwave} AND ${album.genre} NOT LIKE %{Vaporwave}"

[collections.vapor_memory]
label = "Vapor Memory"
filter = "COALESCE(${album.tags.collection}, '') LIKE %{Vapor Memory} OR ${album.genre} LIKE %{Vaporwave}"

[collections.signalwave]
label = "Signal Memory"
filter = "COALESCE(${album.genre}, '') LIKE %{Signalwave}"

# Apple Music Collection

[collections.apple_music]
label = "Apple Music"
filter = "${album.tags.unix_added_applemusic} IS NOT NULL"
strict = true
groupers =["year_added_applemusic", "genre", "decade"]
sorters = ["unix_added_applemusic", "default", "az", "year"]

[groupers.year_added_applemusic]
label = "Year Added"
select = "strftime({%Y}, datetime(${album.tags.unix_added_applemusic}, {unixepoch}))"
strict = true

[sorters.unix_added_applemusic]
label = "Date Added"
order_by = "CAST(${album.tags.unix_added_applemusic} AS INT) DESC"
strict = true

# Foobar2000 Collection

[collections.foobar]
label = "Foobar2000"
filter = "${album.tags.unix_added_foobar} IS NOT NULL"
strict = true
groupers = ["year_added_foobar"]
sorters =["unix_added_foobar"]

[groupers.year_added_foobar]
label = "Year Added"
select = "strftime({%Y}, datetime(${album.tags.unix_added_foobar}, {unixepoch}))"
strict = true

[sorters.unix_added_foobar]
label = "Date Added"
order_by = "CAST(${album.tags.unix_added_foobar} AS INT) DESC"
strict = true

# My Year

[collections.my_year]
label = "My Year"
filter = "${album.tags.my_year} IS NOT NULL"
strict = true
groupers = ["my_year_grouper"]
sorters = ["default", "date_added"]

[groupers.my_year_grouper]
label = "Year"
select = "${album.tags.my_year}"
strict = true

# -- SHELVES --

